#!/usr/bin/env node
/**
 * compose-clawhub-digest.js, Generates providers/clawhub/skills/goshippo/SKILL.md
 * from the SKILL.md.template + canonical skills/<name>/SKILL.md bodies.
 *
 * Hybrid model: framing sections (Setup, Error Handling, Security) are
 * hand-curated in the template; workflow sections are placeholders
 * ({{skill:<name>}}) that get replaced with canonical bodies during compose.
 *
 * The output is auto-generated. Edit the template (for framing/order) or
 * canonical skills/<name>/SKILL.md (for workflow content), not the output.
 */

const fs = require('fs').promises;
const path = require('path');

const ROOT = path.resolve(__dirname, '..');
const SKILLS_DIR = path.join(ROOT, 'skills');
const BUNDLE_DIR = path.join(ROOT, 'providers/clawhub/skills/goshippo');
const TEMPLATE_PATH = path.join(BUNDLE_DIR, 'SKILL.md.template');
const OUTPUT_PATH = path.join(BUNDLE_DIR, 'SKILL.md');

const PLACEHOLDER_RE = /\{\{skill:([a-z0-9-]+)\}\}/g;
const TEMPLATE_HTML_BANNER_RE = /^<!--[\s\S]*?-->\n+/;

function autoGeneratedBanner() {
  return [
    '<!--',
    '  ⚠️  AUTO-GENERATED, do NOT edit this file. Composed from',
    '  providers/clawhub/skills/goshippo/SKILL.md.template + canonical',
    '  skills/<name>/SKILL.md by scripts/compose-clawhub-digest.js.',
    '  Edit the template (for framing) or canonical (for workflow content),',
    '  then run `npm run sync`.',
    '-->',
    '',
    ''
  ].join('\n');
}

async function loadCanonicalBody(skillName) {
  const skillPath = path.join(SKILLS_DIR, skillName, 'SKILL.md');
  let content;
  try {
    content = await fs.readFile(skillPath, 'utf8');
  } catch (err) {
    throw new Error(`Could not read canonical skill ${skillName} at ${skillPath}: ${err.message}`);
  }

  // Strip frontmatter (everything between first --- and second ---)
  const fmMatch = content.match(/^---\n[\s\S]*?\n---\n([\s\S]*)$/);
  let body = fmMatch ? fmMatch[1] : content;

  body = body.trimStart();

  // Strip leading H1 (the body's own title) if present, the digest provides its
  // own ## section header, so we don't need the canonical's # header repeated.
  body = body.replace(/^# [^\n]+\n+/, '');

  // Demote remaining headers by one level (## → ###, ### → ####, etc.) so they
  // nest correctly under the digest's ## section header.
  body = body.replace(/^(#+) /gm, '#$1 ');

  return body.trimEnd();
}

async function main() {
  let template;
  try {
    template = await fs.readFile(TEMPLATE_PATH, 'utf8');
  } catch (err) {
    throw new Error(`Could not read template at ${TEMPLATE_PATH}: ${err.message}`);
  }

  // Strip the leading HTML comment banner from the template (it's for
  // template-readers; the output gets its own AUTO-GENERATED banner).
  template = template.replace(TEMPLATE_HTML_BANNER_RE, '');

  // Find and substitute all {{skill:<name>}} placeholders.
  const placeholders = [...template.matchAll(PLACEHOLDER_RE)];
  let output = template;
  const skillsSeen = new Set();
  for (const m of placeholders) {
    const skillName = m[1];
    skillsSeen.add(skillName);
    const body = await loadCanonicalBody(skillName);
    // Replace this specific occurrence (in case the same skill appears twice).
    output = output.replace(m[0], body);
  }

  // Sanity check: after stripping the template's own HTML banner, the
  // remaining content must start with --- (frontmatter) so the output is
  // a valid skills-ref-shaped file.
  if (!output.startsWith('---\n')) {
    throw new Error('After banner strip, template does not start with frontmatter delimiter. Template structure may be wrong.');
  }

  // NOTE: previously we injected an AUTO-GENERATED HTML-comment banner here.
  // Removed because (a) HTML comments are still bytes the published bundle
  // ships to ClawHub and they're token-wasteful for LLM consumers, and
  // (b) the existing `scripts/check-no-generated-edits.sh` CI step already
  // fails any PR that direct-edits this file, so the in-file warning is
  // belt-and-suspenders. The template (SKILL.md.template) still carries its
  // own "HAND-CURATED TEMPLATE" banner for developers who open the source
  // file. See `autoGeneratedBanner()` (still defined but unused) if the
  // banner ever needs to come back.

  await fs.writeFile(OUTPUT_PATH, output, 'utf8');
  console.log(`Wrote ${path.relative(ROOT, OUTPUT_PATH)}`);
  console.log(`Substituted ${placeholders.length} placeholders for ${skillsSeen.size} unique skills:`);
  for (const name of skillsSeen) {
    console.log(`  ✓ ${name}`);
  }
}

main().catch(err => {
  console.error(err.message || err);
  process.exit(1);
});
